<?php
$pageTitle='Audit Controls';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('audit_controls');
$pdo=getDB();
$users=$pdo->query('SELECT id,email,first_name,last_name FROM '.table('users').' WHERE can_login_erp=1 AND status="active" ORDER BY email')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='create_control'){
      $code=trim((string)$_POST['control_code']);if($code===''){$code=nextScopedDocumentNumber($pdo,'audit_control',setting('audit_control_prefix','CTRL'),operationalScope($pdo));}
      $pdo->prepare('INSERT INTO '.table('audit_controls').' (control_code,control_name,category,risk_level,frequency,owner_user_id,status,description) VALUES (?,?,?,?,?,?,"active",?)')->execute([$code,trim((string)$_POST['control_name']),trim((string)$_POST['category']),trim((string)$_POST['risk_level']),trim((string)$_POST['frequency']),(int)($_POST['owner_user_id']??0)?:null,trim((string)$_POST['description'])]);
      flash('success','Audit control created.');
    }elseif($action==='add_finding'){
      $pdo->prepare('INSERT INTO '.table('audit_control_findings').' (audit_control_id,test_date,result,severity,finding_notes,remediation_status,due_date) VALUES (?,?,?,?,?,"open",?)')->execute([(int)$_POST['audit_control_id'],trim((string)$_POST['test_date']),trim((string)$_POST['result']),trim((string)$_POST['severity']),trim((string)$_POST['finding_notes']),trim((string)($_POST['due_date']??''))?:null]);
      flash('success','Audit test/finding recorded.');
    }elseif($action==='close_finding'){
      $pdo->prepare('UPDATE '.table('audit_control_findings').' SET remediation_status="closed",closed_at=NOW() WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Finding closed.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'audit-controls']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/audit-controls.php');
}
$controls=$pdo->query('SELECT c.*,u.email owner_email,(SELECT COUNT(*) FROM '.table('audit_control_findings').' f WHERE f.audit_control_id=c.id AND f.remediation_status<>"closed") open_findings FROM '.table('audit_controls').' c LEFT JOIN '.table('users').' u ON u.id=c.owner_user_id ORDER BY c.category,c.control_code')->fetchAll();
$findings=$pdo->query('SELECT f.*,c.control_code,c.control_name FROM '.table('audit_control_findings').' f LEFT JOIN '.table('audit_controls').' c ON c.id=f.audit_control_id ORDER BY f.created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Internal Controls</div><h2 class="h4 mb-1">Audit Controls</h2><p class="text-secondary mb-0">Define controls, record audit tests, track findings, and close remediation items.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/security-center.php"><?php echo t('Security Center', 'مركز الأمان'); ?></a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="create_control"><h2 class="h5 mb-3">Create Control</h2><input class="form-control mb-2" name="control_code" placeholder="Auto if blank"><input class="form-control mb-2" name="control_name" placeholder="Control name" required><input class="form-control mb-2" name="category" placeholder="Category"><select class="form-select mb-2" name="risk_level"><option value="low">Low</option><option value="medium" selected>Medium</option><option value="high">High</option></select><select class="form-select mb-2" name="frequency"><option value="monthly">Monthly</option><option value="quarterly">Quarterly</option><option value="annual">Annual</option></select><select class="form-select mb-2" name="owner_user_id"><option value="0">No owner</option><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc($u['email']); ?></option><?php endforeach; ?></select><textarea class="form-control mb-3" name="description" rows="3" placeholder="Control description"></textarea><button class="btn btn-brand w-100">Create Control</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="add_finding"><h2 class="h5 mb-3">Record Test / Finding</h2><select class="form-select mb-2" name="audit_control_id"><?php foreach($controls as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['control_code'].' · '.$c['control_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="date" name="test_date" value="<?php echo esc(date('Y-m-d')); ?>"><select class="form-select mb-2" name="result"><option value="passed">Passed</option><option value="failed">Failed</option><option value="exception">Exception</option></select><select class="form-select mb-2" name="severity"><option value="low">Low</option><option value="medium">Medium</option><option value="high">High</option></select><textarea class="form-control mb-2" name="finding_notes" rows="3" placeholder="Finding / evidence notes"></textarea><label class="form-label">Due Date</label><input class="form-control mb-3" type="date" name="due_date"><button class="btn btn-outline-primary w-100">Record Test</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Controls</h2><table class="table align-middle"><thead><tr><th>Control</th><th>Category</th><th>Risk</th><th>Frequency</th><th>Owner</th><th>Open Findings</th></tr></thead><tbody><?php foreach($controls as $c): ?><tr><td><strong><?php echo esc($c['control_code']); ?></strong><div class="small text-secondary"><?php echo esc($c['control_name']); ?></div></td><td><?php echo esc($c['category']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($c['risk_level']==='high'?'fail':($c['risk_level']==='medium'?'warning':'ok'))); ?>"><?php echo esc($c['risk_level']); ?></span></td><td><?php echo esc($c['frequency']); ?></td><td><?php echo esc($c['owner_email']?:'—'); ?></td><td><?php echo (int)$c['open_findings']; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Findings</h2><table class="table align-middle"><thead><tr><th>Date</th><th>Control</th><th>Result</th><th>Severity</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($findings as $f): ?><tr><td><?php echo esc($f['test_date']); ?></td><td><strong><?php echo esc($f['control_code']); ?></strong><div class="small text-secondary"><?php echo esc($f['finding_notes']); ?></div></td><td><span class="badge bg-<?php echo esc(statusTone($f['result'])); ?>"><?php echo esc($f['result']); ?></span></td><td><?php echo esc($f['severity']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($f['remediation_status'])); ?>"><?php echo esc($f['remediation_status']); ?></span></td><td><?php if($f['remediation_status']!=='closed'): ?><form method="post"><input type="hidden" name="action" value="close_finding"><input type="hidden" name="id" value="<?php echo (int)$f['id']; ?>"><button class="btn btn-sm btn-outline-success">Close</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$findings): ?><tr><td colspan="6" class="text-secondary">No findings yet.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>